export function getTraitsForRace(race: string): typeof TRAITS {
  return TRAITS.filter(t => t.raceBonus.length === 0 || t.raceBonus.some(r => r === race));
}

export function rollTraitsForCharacter(race: string, count = 3): string[] {
  const available = getTraitsForRace(race);
  const prioritized = available.filter(t => t.raceBonus.some(r => r === race));
  const others = available.filter(t => !t.raceBonus.some(r => r === race));
  const shuffled = [...prioritized, ...others];
  const selected: string[] = [];
  for (let i = 0; i < shuffled.length && selected.length < count; i++) {
    const r = Math.random();
    if (r < 0.6 || selected.length < 2) selected.push(shuffled[i].key);
  }
  return selected.slice(0, count);
}

