export function getSettlementById(id: string): Settlement | null {
  return SETTLEMENTS.find(s => s.id === id) || null;
}

export function getSettlementsForRegion(regionKey: string): Settlement[] {
  return SETTLEMENTS.filter(s => s.regionKey === regionKey);
}

