export function getFactionByKey(key: string) {
  return FACTIONS.find(f => f.key === key) || null;
}

export function getRankForReputation(factionKey: string, reputation: number): string {
  const faction = getFactionByKey(factionKey);
  if (!faction) return "Неизвестный";
  let rank = faction.ranks[0];
  for (let i = 0; i < faction.repThresholds.length; i++) {
    if (reputation >= faction.repThresholds[i]) rank = faction.ranks[i];
    else break;
  }
  return rank;
}

export function getNextRankInfo(factionKey: string, reputation: number): { nextRank: string | null; needed: number } {
  const faction = getFactionByKey(factionKey);
  if (!faction) return { nextRank: null, needed: 0 };
  for (let i = 0; i < faction.repThresholds.length; i++) {
    if (reputation < faction.repThresholds[i]) {
      return { nextRank: faction.ranks[i], needed: faction.repThresholds[i] - reputation };
    }
  }
  return { nextRank: null, needed: 0 };
}

function rollRarity(): string {
  const roll = Math.random() * 100;
  if (roll < 3) return "Mythic";
  if (roll < 10) return "Legendary";
  if (roll < 20) return "Epic";
  if (roll < 35) return "Rare";
  if (roll < 60) return "Uncommon";
  return "Common";
}

function getRaceByRarity(rarity: string) {
  const pool = RACES.filter(r => r.rarity === rarity);
  if (!pool.length) {
    const fallback = RACES.filter(r => r.rarity === "Common");
    return fallback[Math.floor(Math.random() * fallback.length)];
  }
  return pool[Math.floor(Math.random() * pool.length)];
}

function getClassByRarity(rarity: string) {
  const pool = CLASSES.filter(c => c.rarity === rarity);
  if (!pool.length) {
    const fallback = CLASSES.filter(c => c.rarity === "Common");
    return fallback[Math.floor(Math.random() * fallback.length)];
  }
  return pool[Math.floor(Math.random() * pool.length)];
}

export function generateCharacter() {
  const raceRarity = rollRarity();
  const classRarity = rollRarity();
  const race = getRaceByRarity(raceRarity);
  const cls = getClassByRarity(classRarity);

  const synergyData = SYNERGIES[race.name];
  const hasSynergy = !!(synergyData && synergyData.classes.includes(cls.name));
  const synergyBonus = hasSynergy ? synergyData.bonus : null;

  const suggestedStats = generateBaseStats(race.name, cls.name);

  return {
    race: race.name,
    raceRarity: race.rarity,
    raceDropChance: race.dropChance,
    raceDescription: race.description,
    raceAbilities: race.abilities,
    raceLifespan: race.lifespan,
    class: cls.name,
    classRarity: cls.rarity,
    classDropChance: cls.dropChance,
    classDescription: cls.description,
    classAbilities: cls.abilities,
    hasSynergy,
    synergyBonus,
    suggestedStats,
  };
}

function generateBaseStats(race: string, className: string): Record<string, number> {
  const base = { strength: 10, agility: 10, intelligence: 10, endurance: 10, luck: 10, charisma: 10, will: 10 };
  const points = 15;
  const keys = Object.keys(base) as (keyof typeof base)[];

  const classWeights: Record<string, Partial<typeof base>> = {
    "Воин": { strength: 5, endurance: 4, agility: 3, will: 2, charisma: 1 },
    "Плут": { agility: 5, luck: 4, strength: 3, intelligence: 2, will: 1 },
    "Маг": { intelligence: 6, will: 4, luck: 3, agility: 2 },
    "Жрец": { will: 5, intelligence: 4, charisma: 4, endurance: 2 },
    "Некромант": { intelligence: 5, will: 5, luck: 3, endurance: 2 },
    "Берсеркер": { strength: 6, endurance: 5, agility: 3, will: 1 },
    "Паладин": { strength: 4, will: 4, endurance: 4, charisma: 3 },
    "Убийца": { agility: 6, luck: 4, strength: 3, intelligence: 2 },
    "Кровавый маг": { intelligence: 5, will: 4, luck: 3, endurance: 3 },
    "Жнец душ": { will: 6, intelligence: 4, luck: 3, charisma: 2 },
    "Рыцарь пустоты": { strength: 4, will: 5, intelligence: 3, endurance: 3 },
    "Владыка смерти": { will: 6, intelligence: 5, charisma: 3, luck: 1 },
  };

  const weights = classWeights[className];
  if (weights) {
    for (const [key, val] of Object.entries(weights)) {
      (base as Record<string, number>)[key] += val as number;
    }
  } else {
    let remaining = points;
    while (remaining > 0) {
      const key = keys[Math.floor(Math.random() * keys.length)];
      base[key]++;
      remaining--;
    }
  }

  return base;
}

