export function getNextWeather(current: string): string {
  const weathers = WEATHER_CONDITIONS.map(w => w.key);
  if (Math.random() < 0.4) return current; // 40% сохранить
  return weathers[Math.floor(Math.random() * weathers.length)];
}

export function advanceTimeOfDay(current: string): string {
  const times = TIME_OF_DAY.map(t => t.key);
  const idx = times.indexOf(current);
  return times[(idx + 1) % times.length];
}

