const CONTRACT_DESCRIPTIONS: Record<string, string[]> = {
  undead: ["Это существо терроризирует округу. Уничтожь его.", "Охотники бегут — ты нет. Задание: ликвидировать."],
  beast:  ["Зверь пожирает торговцев. Нужна голова.", "Тварь стала проблемой. Заказчик платит хорошо."],
  humanoid: ["Отступник должен быть найден и остановлен.", "Предатель с ценой на голове. Живым или мёртвым."],
  demon:  ["Демон прорвался. Печать сломана. Исправь это.", "Существо из Преисподней. Задание не из лёгких."],
  spirit: ["Дух не уходит. Упокой его — навсегда.", "Призрак блокирует проход. Ликвидировать."],
};

export function generateContracts(level: number, count = 3): Array<{
  id: string; target: string; targetType: string; reward: number;
  expiresIn: number; completed: boolean; description: string;
}> {
  const levelMod = Math.max(1, Math.floor(level / 3));
  const shuffled = [...CONTRACT_POOL].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count).map((c, i) => {
    const descs = CONTRACT_DESCRIPTIONS[c.targetType] || ["Выполни задание."];
    const desc = descs[Math.floor(Math.random() * descs.length)];
    return {
      id: `c_${Date.now()}_${i}`,
      target: c.target,
      targetType: c.targetType,
      reward: Math.floor(c.baseReward * (1 + levelMod * 0.2) + Math.random() * 30),
      expiresIn: 8 + Math.floor(Math.random() * 7),
      completed: false,
      description: desc,
    };
  });
}

