export function getDungeonById(id: string) {
  return DUNGEONS_CATALOG.find(d => d.id === id) || null;
}

export function getDungeonsForRegion(region: string) {
  return DUNGEONS_CATALOG.filter(d => d.region === region);
}

export function getDungeonsForLevel(level: number) {
  return DUNGEONS_CATALOG.filter(d => d.minLevel <= level);
}

