export function checkEnding(session: {
  moralAlignment: string;
  factionKey: string | null;
  factionReputation: number;
  killCount: number;
  finalBossDefeated: boolean;
  level: number;
}): string | null {
  for (const ending of HIDDEN_ENDINGS) {
    const c = ending.conditions as Record<string, unknown>;
    if (c.finalBossDefeated && !session.finalBossDefeated) continue;
    if (Array.isArray(c.moralAlignment) && !c.moralAlignment.includes(session.moralAlignment)) continue;
    if (c.minReputation && session.factionReputation < (c.minReputation as number)) continue;
    if (c.maxReputation && session.factionReputation > (c.maxReputation as number)) continue;
    if (c.minKills && session.killCount < (c.minKills as number)) continue;
    if (c.maxKills && session.killCount > (c.maxKills as number)) continue;
    if (c.requiresFaction && !session.factionKey) continue;
    if (c.noFaction && session.factionKey) continue;
    if (c.minLevel && session.level < (c.minLevel as number)) continue;
    return ending.key;
  }
  return null;
}

